import React from "react";
import logo from "../assets/Logo.png"; // path to your uploaded logo
import "./Logo.css";

const Logo = () => {
  return (
    <header className="Logo">
      <img src={logo} alt="Agranika Logo" className="logo" />
      <h1 className="site-title">Agranika</h1>
    </header>
  );
};

export default Logo;
